module top_module(
    input clk,
    input [3:0] D,
    input SI,
    output reg SO
);reg [3:0] shift_reg;

    always @(posedge clk) begin
        if (SI) begin
            shift_reg <= {shift_reg[2:0], SI};
        end else begin
            shift_reg <= D;
        end
    end

    assign SO = shift_reg[0];

endmodule
